	private static void applyJoinEstimates(Join join, JoinOptimizationContext ctx) {
		if (!ctx.getStats().supportsJoinEstimation()) {
			return;
		}
		double estimate = ctx.getStats().getCardinality(join);
		if (!Double.isFinite(estimate) || estimate < 0) {
			return;
		}
		join.setResultSizeEstimate(Math.max(estimate, join.getResultSizeEstimate()));
		join.setCostEstimate(Math.max(estimate, join.getCostEstimate()));
	}
